// Gelen mesajın tipini tespit et
const msg = $input.item.json.message;
const chatId = msg.chat.id;
const userId = msg.from.id;
const firstName = msg.from.first_name || 'Kullanıcı';

let messageType = 'text';
let content = '';
let fileId = null;

if (msg.voice) {
  messageType = 'voice';
  fileId = msg.voice.file_id;
  content = '[Sesli mesaj alındı, transkripsiyon yapılıyor...]';
} else if (msg.audio) {
  messageType = 'audio';
  fileId = msg.audio.file_id;
  content = '[Ses dosyası alındı]';
} else if (msg.text) {
  messageType = 'text';
  content = msg.text;
}

return [{ json: {
  chatId,
  userId,
  firstName,
  messageType,
  content,
  fileId,
  isVoice: messageType === 'voice' || messageType === 'audio',
  rawMessage: msg
}}];

// Whisper çıktısından transcript'i al
const transcript = $input.item.json.text || '';
const prev = $node['Mesaj Tipini Tespit Et'].json;

return [{ json: {
  ...prev,
  content: transcript,
  transcriptionDone: true
}}];

