const responseText = $input.item.json.candidates[0].content.parts[0].text;
const chatId = $node['Mesaj Tipini Tespit Et'].json.chatId;
let parsed;
try {
  const cleaned = responseText.replace(/```json|```/g, '').trim();
  parsed = JSON.parse(cleaned);
} catch(e) {
  parsed = { classification: 'parse_error', action_items: [] };
}
return [{ json: { ...parsed, chatId, parseError: !parsed.meeting_title } }];
